"""Unit tests for agent tracking logic in the controller.

Tests effective_state priority, agent lifecycle edge cases, and debounce bypass.
These are unit tests that don't require a running HTTP server or Tkinter.
"""

from claude_dashboard.config import StatusState
from claude_dashboard.controller import _AgentEntry, _SessionEntry, _STATE_PRIORITY
from claude_dashboard.session import SessionInfo


def _make_session(*, pid: int = 1000, cwd: str = "/tmp/test") -> SessionInfo:
    return SessionInfo(pid=pid, session_id="test-sid", cwd=cwd, started_at=0)


class TestEffectiveState:
    """Test _SessionEntry.effective_state property (FR-037)."""

    def test_no_agents_returns_main_state(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.IDLE
        assert entry.effective_state == StatusState.IDLE

    def test_agent_higher_priority_overrides_main(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.IDLE
        entry.agents["a1"] = _AgentEntry(
            agent_id="a1",
            state=StatusState.PERMISSION_REQUIRED,
        )
        assert entry.effective_state == StatusState.PERMISSION_REQUIRED

    def test_main_higher_priority_than_agent(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.PERMISSION_REQUIRED
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.IDLE)
        assert entry.effective_state == StatusState.PERMISSION_REQUIRED

    def test_multiple_agents_highest_wins(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.IDLE
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        entry.agents["a2"] = _AgentEntry(
            agent_id="a2",
            state=StatusState.AWAITING_INPUT,
        )
        assert entry.effective_state == StatusState.AWAITING_INPUT

    def test_all_states_in_priority_order(self):
        """Verify the full priority chain: PERM > AWAIT > WORKING > READY > IDLE."""
        ordered = [
            StatusState.PERMISSION_REQUIRED,
            StatusState.AWAITING_INPUT,
            StatusState.WORKING,
            StatusState.READY,
            StatusState.IDLE,
        ]
        for i, higher in enumerate(ordered):
            for lower in ordered[i + 1 :]:
                entry = _SessionEntry(_make_session())
                entry.state = lower
                entry.agents["a1"] = _AgentEntry(agent_id="a1", state=higher)
                assert entry.effective_state == higher, f"{higher.value} should beat {lower.value}"

    def test_empty_agents_dict_no_error(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.IDLE
        assert entry.agents == {}
        assert entry.effective_state == StatusState.IDLE

    def test_agent_same_state_as_main(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.WORKING
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        assert entry.effective_state == StatusState.WORKING


